use std::sync::RwLock;

// Simple brute-force vector database with optional parallel search.
// Stores vectors in a Vec to be cache-friendly for linear scans.
// Uses an auxiliary index Vec to allow deletes (swap-remove) if needed.
// For now, we don't delete, so we just append.
// We keep a RwLock to allow concurrent reads and exclusive writes.

struct Entry {
    id: u64,
    vector: Vec<f32>,
}

pub struct VectorDB {
    entries: RwLock<Vec<Entry>>,
}

impl VectorDB {
    pub fn new() -> Self {
        Self {
            entries: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        // Basic validation
        assert_eq!(vector.len(), 128, "Vector must be 128-dimensional");
        let mut entries = self.entries.write().unwrap();
        entries.push(Entry { id, vector });
    }

    pub fn bulk_insert(&self, vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let mut entries = self.entries.write().unwrap();
        let before = entries.len();
        for (id, vector) in vectors {
            assert_eq!(vector.len(), 128, "Vector must be 128-dimensional");
            entries.push(Entry { id, vector });
        }
        entries.len() - before
    }

    pub fn search(&self, vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        assert_eq!(vector.len(), 128, "Query vector must be 128-dimensional");
        let entries = self.entries.read().unwrap();
        let n = entries.len();
        if n == 0 || top_k == 0 {
            return Vec::new();
        }

        // Use a small fixed buffer for partial top-k to avoid full sort when possible.
        // But for correctness and simplicity (and because recall must be exact),
        // we compute all distances and then select top-k.
        // We will try to make distance computation fast and the selection efficient.

        // For better performance, we can use an order-statistic selection or a binary heap.
        // Use a max-heap of size top_k to keep the smallest distances.
        use std::cmp::Reverse;
        use std::collections::BinaryHeap;

        let k = top_k as usize;
        let mut heap = BinaryHeap::with_capacity(k + 1);

        // If the dataset is large, using Rayon for parallel distance computation helps.
        // But aggregation into a single heap requires care. We'll do a simple serial version first,
        // then try a parallel version using chunks and merge.

        for entry in entries.iter() {
            let d = crate::distance::l2_distance(vector, &entry.vector);
            // Push (distance, id). We want min distances, so use Reverse or invert ordering.
            // Use Reverse<f64> for min-heap behavior by distance, but we want a max-heap
            // of the k smallest, so we store (d, id) and keep the largest of the k at the top.
            // Use a tuple (OrderedFloat, id) to allow f64 in BinaryHeap.
            use std::cmp::Ordering;
            #[derive(PartialEq)]
            struct DistId {
                d: f64,
                id: u64,
            }
            impl Eq for DistId {}
            impl PartialOrd for DistId {
                fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
                    // Reverse order for max-heap by distance
                    other.d.partial_cmp(&self.d)
                }
            }
            impl Ord for DistId {
                fn cmp(&self, other: &Self) -> Ordering {
                    self.partial_cmp(other).unwrap_or(Ordering::Equal)
                }
            }

            let item = DistId { d, id: entry.id };
            if heap.len() < k {
                heap.push(item);
            } else {
                // If this distance is smaller than the largest in heap, replace
                if let Some(top) = heap.peek() {
                    if item.d < top.d {
                        heap.pop();
                        heap.push(item);
                    }
                }
            }
        }

        // Extract results and sort ascending by distance
        let mut results: Vec<_> = heap.into_iter().map(|x| SearchResult { id: x.id, distance: x.d }).collect();
        results.sort_by(|a, b| a.distance.partial_cmp(&b.distance).unwrap_or(Ordering::Equal));
        results
    }
}
"}

