{"path": "src/distance.rs", "content": "pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    // Optimized safe version with loop unrolling and f64 accumulator.
    assert_eq!(a.len(), b.len());
    let n = a.len();
    let mut sum = 0.0f64;
    let mut i = 0;
    // Unroll by 4 to reduce loop overhead and allow better ILP
    while i + 4 <= n {
        let d0 = (a[i] - b[i]) as f64;
        let d1 = (a[i + 1] - b[i + 1]) as f64;
        let d2 = (a[i + 2] - b[i + 2]) as f64;
        let d3 = (a[i + 3] - b[i + 3]) as f64;
        sum += d0 * d0 + d1 * d1 + d2 * d2 + d3 * d3;
        i += 4;
    }
    while i < n {
        let d = (a[i] - b[i]) as f64;
        sum += d * d;
        i += 1;
    }
    sum
}
"}

